const normalize = (val) => String(val).trim().toLowerCase().replace(/^minecraft:/, '').replace(/\s+/g, '_');
const reqItem = normalize(args.itemName);
const getTeammate = () => bot.players[args.targetPlayerName]?.entity;
if (!bot.entity || bot.health <= 0) return '<UNSAFE>: Bot is not alive.';
const invItem = bot.inventory.items().find(i => normalize(i.name) === reqItem || normalize(i.displayName) === reqItem);
if (!invItem) return '<NO ITEM>: Missing ' + args.itemName + ' in inventory.';
const teammate = getTeammate();
if (!teammate) return '<NO TARGET>: Teammate ' + args.targetPlayerName + ' not found or too far.';

startBackgroundSkill(bot, 'build_cover', async function(token) {
  const pollMs = 100;
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);

  try {
    if (!await waitUntilWorldActive(bot, token, pollMs)) return;
    await bot.equip(invItem, 'hand');

    const currentTeammate = getTeammate();
    if (!currentTeammate || !canContinueBotAction(bot, token)) return;

    const nearestHostile = bot.nearestEntity(e => (e.kind === 'Hostile mobs' || e.type === 'hostile' || e.type === 'mob') && e.position.distanceTo(currentTeammate.position) < 20);
    let direction;
    if (nearestHostile) {
      direction = nearestHostile.position.minus(currentTeammate.position).normalize();
    } else {
      direction = bot.entity.position.minus(currentTeammate.position).normalize();
    }

    const placementBase = currentTeammate.position.plus(direction.scaled(args.pillarDistance)).floored();
    const approachPos = placementBase.offset(0, 0, 0);

    bot.pathfinder.setGoal(new goals.GoalNear(approachPos.x, approachPos.y, approachPos.z, 3));
    while (canContinueBotAction(bot, token) && bot.entity.position.distanceTo(approachPos) > 3.5) {
      if (!await waitForActiveMs(bot, token, pollMs)) return;
    }
    bot.pathfinder.setGoal(null);

    let blocksPlaced = 0;
    for (let i = 0; i < args.maxBlocks; i++) {
      if (!canContinueBotAction(bot, token)) return;
      const targetY = placementBase.y + i;
      const targetPos = new Vec3(placementBase.x, targetY, placementBase.z);

      const currentBlock = bot.blockAt(targetPos);
      if (currentBlock && currentBlock.name !== 'air' && currentBlock.name !== 'water' && currentBlock.name !== 'lava') continue;

      const refBlock = bot.blockAt(targetPos.offset(0, -1, 0));
      if (!refBlock || refBlock.name === 'air') break;

      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
      const handItem = bot.inventory.items().find(it => normalize(it.name) === reqItem);
      if (!handItem) break;
      await bot.equip(handItem, 'hand');

      await bot.lookAt(refBlock.position.offset(0.5, 1, 0.5), true);
      try {
        await bot.placeBlock(refBlock, new Vec3(0, 1, 0));
        blocksPlaced++;
      } catch (err) {}
      await waitForActiveMs(bot, token, 200, pollMs);
    }
  } finally {
    bot.pathfinder.setGoal(null);
  }
});

return '<STARTED>: Deploying ' + args.itemName + ' cover for ' + args.targetPlayerName + '.';
